import sys
import os

def read_fixed_file(filepath, record_size):
    if not os.path.exists(filepath):
        return []
    with open(filepath, 'rb') as f:
        records = []
        while True:
            chunk = f.read(record_size)
            if not chunk:
                break
            if len(chunk) < record_size:
                chunk = chunk.ljust(record_size, b'\x00')
            records.append(chunk)
    return records

def format_balance(bal):
    return f"{bal:010d}".encode('ascii')

def main():
    try:
        with open("src/INPUT.DAT", "rb") as f:
            raw_data = f.read(22)
    except FileNotFoundError:
        print("Error: Input file is empty")
        return

    if not raw_data:
        print("Error: Input file is empty")
        sys.exit(0)

    if len(raw_data) < 22:
        raw_data = raw_data.ljust(22, b'\x00')

    buyer_id = raw_data[0:4]
    seller_id = raw_data[4:8]
    ws_book_id = raw_data[8:12]
    amount_raw = raw_data[12:22]

    amount_str = bytearray()
    for b in amount_raw:
        if b == 0x00 or b == 0x20:
            amount_str.append(0x30)
        else:
            amount_str.append(b)

    try:
        ws_amount = int(amount_str.decode('latin1'))
    except ValueError:
        ws_amount = 0
        for b in amount_str:
            ws_amount = ws_amount * 10 + (b - 0x30)

    ws_amount = abs(ws_amount) % (10**10)

    buyer_found = False
    seller_found = False
    book_found = False
    valid_owner = False

    accounts = read_fixed_file("data/ACCOUNTS.DAT", 34)
    for rec in accounts:
        acc_id = rec[0:4]
        if acc_id == buyer_id:
            buyer_found = True
        if acc_id == seller_id:
            seller_found = True

    books = read_fixed_file("data/BOOKS.DAT", 28)
    for rec in books:
        book_id = rec[0:4]
        if book_id == ws_book_id:
            book_found = True
            book_owner = rec[24:28]
            if book_owner == seller_id:
                valid_owner = True

    if buyer_found and seller_found and book_found and valid_owner:
        pass
    else:
        print("Transaction failed due to validation errors")
        sys.exit(0)

    # REWRITE accounts
    with open("data/ACCOUNTS.DAT", "r+b") as f:
        while True:
            pos = f.tell()
            record = f.read(34)
            if len(record) < 34:
                break

            acc_id = record[0:4]
            balance = int(record[24:34].decode('ascii'))
            new_balance = balance
            modified = False

            if acc_id == buyer_id:
                new_balance = abs(new_balance - ws_amount) % (10**10)
                modified = True

            if acc_id == seller_id:
                new_balance = (new_balance + ws_amount) % (10**10)
                modified = True

            if modified:
                new_record = record[0:24] + format_balance(new_balance)
                f.seek(pos)
                f.write(new_record)

    # REWRITE books
    with open("data/BOOKS.DAT", "r+b") as f:
        while True:
            pos = f.tell()
            record = f.read(28)
            if len(record) < 28:
                break

            book_id = record[0:4]
            if book_id == ws_book_id:
                new_record = record[0:24] + buyer_id
                f.seek(pos)
                f.write(new_record)

    # WRITE transaction
    trans_record = ws_book_id + format_balance(ws_amount) + seller_id + buyer_id
    with open("data/TRANSACTIONS.DAT", "ab") as f:
        f.write(trans_record)

    print("Transaction completed successfully")

if __name__ == "__main__":
    main()
